<script>
    var searchParams = new URLSearchParams(window.location.search);

    const filter_key = ['ratings','cate_select','price_course'];

    var count_filter = 0;

    updateArrFilter();
    function updateArrFilter(){
        count_filter = 0;
        if($.isArray(arr_filter)){
            arr_filter = {}
        }
        $.each(arr_filter,(k,v) => {
            if(jQuery.inArray(k, filter_key) !== -1){
                if(arr_filter[k].length > 0){
                    count_filter += 1;
                }
            }
        });

        if(count_filter > 0){
            $('.count_filter').text('('+count_filter+')');
            $('.clear_filter').removeClass('hide');
        }
        else{
            $('.count_filter').text('');
            $('.clear_filter').addClass('hide');
        }
    }

    function clearFilter(){
        count_filter = 0;

        filter_key.forEach((v,i) => {
            delete arr_filter[v];
        });

        $('input[name="ratings"]:radio').removeAttr('checked');
        $('input[name="cate_select"]:checkbox').removeAttr('checked');
        $('input[name="price_course"]:checkbox').removeAttr('checked');

        updateParamUrl();
    }
    function showSidebarFilter(){
        if($(window).width() <= 992){
            if($('.sidebar-filter').hasClass('show')){
                $('.body').css('overflow','auto');
                $('.sidebar-filter').removeClass('show');
            }
            else{
                $('.body').css('overflow','hidden');
                $('.sidebar-filter').addClass('show');
            }
        }
    }

    const url_no_param = window.location.origin + window.location.pathname

    function updateParamUrl(type){

        if(type !== 'page'){
            arr_filter.page = 1;
        }
        searchParams = new URLSearchParams(url_no_param.search);
        $.each(arr_filter,(k,val)=> {
            if(typeof val === 'object' && val != null){
                val.forEach((v,i)=> {
                    if(v !== 'undefined'){
                        searchParams.set(k+'['+i+']', v);
                    }
                });
            }
            else{
                searchParams.set(k, val);
            }
        });

        updateArrFilter();

        $('.loading-category').removeClass('hide');

        $.ajax({
            url: url_no_param+"?"+searchParams.toString(),
            method: 'post'
        }).done((res) => {
            if(res.success){
                window.history.pushState('', '', url_no_param+"?"+searchParams.toString());
                location.reload();
                $('html').animate({ scrollTop: 0,}, 100);

                setTimeout(function() {
                    $('.category-list-courses').html(res.html);
                    $('.filter-panel--item-count').text(res.course_count);
                    $('.loading-category').addClass('hide');
                    updateFilter(res.sidebar_cate);
                    if($(".category-list-course img.lazyload").length > 0){
                        $(".category-list-course img.lazyload").lazyload({
                            effect : "fadeIn",
                            threshold: 0.1,
                        });
                    }
                }, 1000);
            }
            else{
                $('.loading-category').addClass('hide');
            }
        }).fail((xhr) => {
            $('.loading-category').addClass('hide');
        })
    };

    function updateSort(el,val){
        $('.btn-custom-category').removeClass('active');
        $(el).addClass('active');
        arr_filter.sort = val;
        updateParamUrl();

    }

    $(document).on('change','input[name="ratings"]',function(){
        if ($(this).is(':checked')) {
            arr_filter.ratings = $(this).val();
            updateParamUrl();
        }
    })

    $(document).on('change','input[name="price_course"]',function(){

        if(typeof arr_filter.price_course == "undefined"){
            arr_filter.price_course = [];
        }

        if(typeof arr_filter.price_course == 'object'){
            arr_filter.price_course  = Object.values(arr_filter.price_course);
        }

        let ind = jQuery.inArray($(this).val(), arr_filter.price_course);
        if(ind === -1){
            arr_filter.price_course.push($(this).val());
            $(this).attr('checked', 'checked');
        }
        else{
            arr_filter.price_course.splice(arr_filter.price_course.indexOf($(this).val()),1);
            $(this).removeAttr('checked');
        }
        updateParamUrl();
    })

    $(document).on('change','input[name="cate_select"]',function(){


        if(typeof arr_filter.cate_select == "undefined"){
            arr_filter.cate_select = [];
        }

        if(typeof arr_filter.cate_select == 'object'){
            arr_filter.cate_select  = Object.values(arr_filter.cate_select);
        }

        let ind = jQuery.inArray($(this).val(), arr_filter.cate_select);
        if(ind === -1){
            arr_filter.cate_select.push($(this).val());
            $(this).attr('checked', 'checked');
        }
        else{
            arr_filter.cate_select.splice(arr_filter.cate_select.indexOf($(this).val()),1);
            $(this).removeAttr('checked');
        }
        updateParamUrl();
    })

    $(document).on('click','.udlite-accordion-panel-toggler',function (){
        if($(this).parents('.panel--panel').find('.accordion-panel').attr('data-checked') == 'checked'){
            $(this).parents('.panel--panel').find('.accordion-panel').attr('data-checked','');
        }
        else{
            $(this).parents('.panel--panel').find('.accordion-panel').attr('data-checked','checked');
        }
    });
    function showMoreFilter(el){
        if($(el).parents('.show-more--container').find('.show-more').attr('data-checked') == 'checked'){
            $(el).parents('.show-more--container').find('.show-more').attr('data-checked','');
        }
        else{
            $(el).parents('.show-more--container').find('.show-more').attr('data-checked','checked');
        }

    }

    // $(document).on('click','.pagination a',function (e){
    //     e.preventDefault();
    //
    //     arr_filter.page = $.urlParam('page',$(this).attr('href'));
    //
    //     updateParamUrl('page');
    // });

    $.urlParam = function(name,url){
        var results = new RegExp('[\?&]' + name + '=([^&#]*)').exec(url);
        if (results==null) {
            return null;
        }
        return decodeURI(results[1]) || 0;
    }
    var html_sidebar_cate = '';
    function updateFilter(sidebar_cate){
        html_sidebar_cate = sidebar_cate;
        if( $(window).width() <= 768){
            $('.filter-content').html('');
            if($('.filter-content-sidebar').html() == ''){
                $('.filter-content-sidebar').html(html_sidebar_cate);
            }
        }
        else{
            $('.filter-content-sidebar').html('');
            if($('.filter-content').html() == ''){
                $('.filter-content').html(html_sidebar_cate);
            }
        }
    }

    function updateFilterResize(){
        // let html = '';
        if($('.sidebar-filter').css('display') == 'none'){
            $('.body').css('overflow','auto');

            html_sidebar_cate = $('.filter-content-sidebar').html();
            if($('.filter-content-sidebar').html() !== ''){

                $('.filter-content-sidebar').html('');
                $('.filter-content').html(html_sidebar_cate);
            }
        }
        else{
            if($('.sidebar-filter').hasClass('show')){
                $('.body').css('overflow','hidden');
            }

            if($('.filter-content').html() !== ''){
                html_sidebar_cate = $('.filter-content').html();
                $('.filter-content').html('');
                $('.filter-content-sidebar').html(html_sidebar_cate);
            }

        }
    }

    updateFilterResize();
    $(window).on('resize',function (){
        updateFilterResize();
    })

    window.onpopstate = function() {
        $('.loading-category').removeClass('hide');

        $.ajax({
            url: window.location.href,
            method: 'post'
        }).done((res) => {
            if(res.success){
                $('html').animate({ scrollTop: 0,}, 100);

                setTimeout(function() {
                    $('.category-list-courses').html(res.html);
                    $('.filter-panel--item-count').text(res.course_count);
                    $('.loading-category').addClass('hide');
                    updateFilter(res.sidebar_cate);
                    arr_filter = res.arr_filter;
                    updateArrFilter();
                    if($(".category-list-course img.lazyload").length > 0){
                        $(".category-list-course img.lazyload").lazyload({
                            effect : "fadeIn",
                            threshold: 0.1,
                        });
                    }
                }, 1500);
            }
            else{
                $('.loading-category').addClass('hide');
            }
        }).fail((xhr) => {
            $('.loading-category').addClass('hide');
        })
    }; history.pushState({}, '' );

    if($('.article--content').height() > 500){
        $('.article--content').css('height','300px');
        $('.article--content--more').removeClass('hide');
    }

    function showContent(el){
        if($('.article--content').css('height') != '300px'){
            $('.article--content').css('height','300px');
            $('.bg-article').removeClass('hide');
            $(el).html('<span>Xem thêm</span>');
        }
        else{
            $('.article--content').css('height','auto');
            $('.bg-article').addClass('hide');
            $(el).html('<span>Thu gọn</span>');
        }
    }
</script>

