<script type="text/javascript">

    function showModalReview(){
        $('.modal-review').modal('show');
    }
    if($('.body-content').offset().top <= 50 + $(window).scrollTop()){
        $('.paid-course').addClass('show-fixed');
        $('.paid-course').removeClass('show-bottom');
    }

    if($('.footer').offset().top <= $(window).scrollTop() + $(window).height()){
        $('.paid-course').addClass('show-bottom');
        $('.paid-course').removeClass('show-fixed');
    }

    $(window).on('scroll',function (){
        if($('.body-content').offset().top <= 50 + $(this).scrollTop()){
            $('.paid-course').addClass('show-fixed');
            $('.paid-course').removeClass('show-bottom');
        }
        else{
            $('.paid-course').removeClass('show-fixed');
        }

        if($('.footer').offset().top <= $(this).scrollTop() + $(window).height()){
            $('.paid-course').addClass('show-bottom');
            $('.paid-course').removeClass('show-fixed');
        }
        else{
            $('.paid-course').removeClass('show-bottom');
        }
    })

    var ajaxRv = false;
    var type_review = 'all';

    function viewMoreReview(star,el){

        if(ajaxRv){
            return;
        }

        let type_review_old = type_review;
        let htmlText = $(el).html();
        if(star != 'same'){
            if(star == type_review){
                $('.btn--more-review').removeClass('hide');
            }
            else{
                type_review = star;
                skip_rv = 0;
                take_rv = 5;
                $('.btn--more-review').removeClass('hide');
            }
        }
        else{
            $(el).html('<div class="lds-ring my-auto mr-2 black"><div></div><div></div><div></div><div></div></div> Hiện thêm đánh giá');
        }

        $.ajax({
            url: '/api/'+course.id+'/get-new-review',
            data: {
                skip: skip_rv,
                take: take_rv,
                type: 'preview',
                star: type_review
            },
            method: 'post'
        }).done((msg)=>{
            if(msg.success) {

                skip_rv = msg.skip_rv;
                if(star != 'same' && star != type_review_old){
                    $('.list_reviews').html(msg.html);
                }
                else{
                    $('.list_reviews').append(msg.html);
                }


                if ($(".list_reviews img.lazyload").length > 0) {
                    $(".list_reviews img.lazyload").lazyload({
                        effect: "fadeIn",
                        threshold: 0.1,
                    });
                }

                $(el).html(htmlText);
                if(msg.review_last){
                    $('.btn--more-review').addClass('hide');
                }
                ajaxRv = false;
            }
            else{
                ajaxRv = false;
                $(el).html(htmlText);
            }

        }).fail((xhr) => {
            ajaxRv = false;
            $(el).html(htmlText);
        });
    }


    var ajaxDis = false;

    function viewMoreDis(el){

        if(ajaxDis){
            return;
        }

        let htmlText = $(el).html();

        $(el).html('<div class="lds-ring my-auto mr-2 black"><div></div><div></div><div></div><div></div></div> '+htmlText);

        $('img[data-enlargable]').addClass('img-enlargable');

        $.ajax({
            url: '/api/'+course.id+'/get-new-discussion',
            data: {
                skip: skip_discussion,
                take: take_discussion
            },
            method: 'post'
        }).done((msg)=>{
            if(msg.success) {

                skip_discussion = msg.skip_discussion;

                $('.discussion-course .list-discussions').append(msg.html);

                if ($(".list-discussions img.lazyload").length > 0) {
                    $(".list-discussions img.lazyload").lazyload({
                        effect: "fadeIn",
                        threshold: 0.1,
                    });
                    $('img[data-enlargable]').addClass('img-enlargable');
                }

                $(el).html(htmlText);

                if(msg.discussion_last){
                    $('.btn--more-discussion').addClass('hide');
                    $('img[data-enlargable]').addClass('img-enlargable');
                }
                ajaxDis = false;
            }
            else{
                ajaxDis = false;
                $(el).html(htmlText);
            }

        }).fail((xhr) => {
            ajaxDis = false;
            $(el).html(htmlText);
        });
    }


    function trackingFbCompleteRegistration() {
        try {
            // Facebook ContentView Tracking
            fbq('track', 'CompleteRegistration',
                {
                    value: 499000,
                    content_ids: '[97]',
                    currency: 'VND',
                    content_name: 'VBAG01: Tuyệt đỉnh VBA  - Tự động hóa Excel với lập trình VBA - CompleteRegistration',
                    status: true
                }
            );
        }
        catch (err) {
            console.error(err);
        }
    }

    var player = null;

    var content_try_id = null;
    var content_try_loading = false;

    function getUrlCdn(){
        const video = document.querySelector("video");
        return video.getElementsByTagName("source")[0].getAttribute('data-url');
    }
    function showVideoTry(content_id,el,htmlTry = '') {

        if(content_try_id === content_id){
            $('.bg-over-load-video').addClass('hide');
            $('.bd-show-video-try-modal-lg').modal('show');
            return;
        }

        if(content_try_loading){
            return;
        }

        content_try_loading = true;

        $('.bg-over-load-video.hide').removeClass('hide');

        $.post('/get-video-try',{content_id:content_id ,course_id:course.id})
            .done(function(data){
                if(data.success){

                    if(!$(el).hasClass('btn-content-try')){
                        $('.content-try-item').not(el).removeClass('active');
                        $(el).addClass('active');
                    }
                    else{
                        $(el).html(htmlTry);
                    }

                    if($(el).attr('data-id') != ''){
                        $('.content-try-item').not(el).removeClass('active');
                        $('#content_try_'+$(el).attr('data-id')).addClass('active');
                    }
                    content_try_id = content_id;
                    $('.bd-show-video-try-modal-lg .lecture_content').html(data.html);
                    $('.bd-show-video-try-modal-lg .text-content-try').html(data.title);

                    $('.bg-over-load-video').addClass('hide');
                    $('.bd-show-video-try-modal-lg').modal('show');
                    content_try_loading = false;
                    $('.bd-show-video-try-modal-lg').animate({
                        scrollTop: 0,
                    }, 200);

                    if(player != null){
                        hls.destroy();
                        player.destroy();
                    }

                    if($( window ).width() > 800){
                        speedOption = { selected: 1, options: [0.5, 1, 1.5, 2] };
                    }
                    var playerSeekTime = 10;
                    if(can_seek_video == 0){
                        playerSeekTime = 0;
                    }
                    const video = document.querySelector("video");
                    // Bài học không phải video

                    if(video == null || video.length == 0){
                        return;
                    }
                    const source = video.getElementsByTagName("source")[0].src;

                    // For more options see: https://github.com/sampotts/plyr/#options
                    const defaultOptions = {};

                    if (Hls.isSupported()) {
                        const hls = new Hls();
                        hls.loadSource(source);

                        hls.on(Hls.Events.MANIFEST_PARSED, function (event, data) {
                            // Transform available levels into an array of integers (height values).
                            const availableQualities = hls.levels.map((l) => l.height);
                            availableQualities.unshift(0) //prepend 0 to quality array

                            // Add new qualities to option
                            defaultOptions.quality = {
                                default: 0, //Default - AUTO
                                options: availableQualities,
                                forced: true,
                                onChange: (e) => updateQuality(e),
                            }
                            // Add Auto Label
                            defaultOptions.i18n = {
                                qualityLabel: {
                                    0: 'Auto',
                                },
                            }

                            hls.on(Hls.Events.LEVEL_SWITCHED, function (event, data) {
                                var span = document.querySelector(".plyr__menu__container [data-plyr='quality'][value='0'] span")
                                if (hls.autoLevelEnabled) {
                                    span.innerHTML = `AUTO (${hls.levels[data.level].height}p)`
                                } else {
                                    span.innerHTML = `AUTO`
                                }
                            })

                            // Initialize here
                            window.player = new Plyr(video, {
                                seekTime: playerSeekTime,
                                speed: speedOption,
                                quality : {
                                    default: 0,
                                    options: availableQualities,
                                    // this ensures Plyr to use Hls to update quality level
                                    forced: true,
                                    onChange: (e) => updateQuality(e),
                                },
                                i18n : {
                                    qualityLabel: {
                                        0: 'Auto',
                                    },
                                },
                                listeners: {
                                    seek: function customSeekBehavior(e) {
                                        var newTime = _getTargetTime(player, e);
                                        if(can_seek_video == 0){
                                            // We only want rewind functionality
                                            // Therefore, disallow moving forward
                                            if (newTime > playerReachTime) {
                                                e.preventDefault();
                                                notifiMessage('Thao tác không được phép. Tính năng này được cài đặt trong doanh nghiệp của bạn', 'danger');
                                                return false;
                                            }
                                        }

                                        return true;
                                    }
                                }
                            });
                            player.on('ended', function (e) {
                                storeStudentContentViewLog(e.detail.plyr.currentTime, current_content_id);
                                nextStudyLecture();
                            });
                            // player.on('pause', function (e) {
                            //     storeStudentContentViewLog(e.detail.plyr.currentTime, current_content_id);
                            // });
                            player.on('timeupdate', function (e) {
                                if(player.currentTime > playerReachTime){
                                    playerReachTime = player.currentTime;
                                }
                            });

                            player.on('error', function (e) {
                                console.error('Doh!', e);
                                return false;
                            });
                        });

                        hls.on(Hls.Events.ERROR, function (event, data) {
                            switch (data.type) {
                                case Hls.ErrorTypes.NETWORK_ERROR:
                                    // try to recover network error
                                    console.log('Video này không thể phát do không thể tải được nội dung.');
                                    break;
                                case Hls.ErrorTypes.MEDIA_ERROR:
                                    console.log('fatal media error encountered, try to recover');
                                    // hls.recoverMediaError();
                                    break;
                                default:
                                    // cannot recover
                                    hls.destroy();
                                    break;
                            }

                        });
                        hls.attachMedia(video);

                        if(video.getElementsByTagName("source")[0].getAttribute('data-type') == 'local'){
                            var fragmentExtension = '.ts';
                            var keyFragmentExtension = '.key';
                            var originalOpen = XMLHttpRequest.prototype.open;

                            XMLHttpRequest.prototype.open = function() {
                                if (arguments[1].endsWith(fragmentExtension) || arguments[1].endsWith(keyFragmentExtension)){
                                    arguments[1] = getUrlCdn() + arguments[1].substring(arguments[1].lastIndexOf('/') + 1);
                                }
                                originalOpen.apply(this, arguments);
                            }
                        }


                        // }


                        window.hls = hls;
                    } else {
                        // default options with no quality update in case Hls is not supported
                        // const player = new Plyr(video, defaultOptions);
                        const player = new Plyr(video, {
                            seekTime: playerSeekTime,
                            // quality : {
                            //     // default: availableQualities[0],
                            //     // options: availableQualities,
                            //     // this ensures Plyr to use Hls to update quality level
                            //     forced: true,
                            //     onChange: (e) => updateQuality(e),
                            // },
                            listeners: {
                                seek: function customSeekBehavior(e) {
                                    var newTime = _getTargetTime(player, e);
                                    if(can_seek_video == 0){
                                        // We only want rewind functionality
                                        // Therefore, disallow moving forward
                                        if (newTime > playerReachTime) {
                                            e.preventDefault();
                                            notifiMessage('Thao tác không được phép. Tính năng này được cài đặt trong doanh nghiệp của bạn', 'danger');
                                            return false;
                                        }
                                    }

                                    return true;
                                }
                            }
                        });
                        player.on('ended', function (e) {
                            storeStudentContentViewLog(e.detail.plyr.currentTime, current_content_id);
                            nextStudyLecture();
                        });
                        player.on('timeupdate', function (e) {
                            if(player.currentTime > playerReachTime){
                                playerReachTime = player.currentTime;
                            }
                        });

                        player.on('error', function (e) {
                            console.error('Doh!', e);
                            return false;
                        });
                    }

                    function updateQuality(newQuality) {
                        if (newQuality === 0) {
                            window.hls.currentLevel = -1; //Enable AUTO quality if option.value = 0
                        } else {
                            window.hls.levels.forEach((level, levelIndex) => {
                                if (level.height === newQuality) {
                                    console.log("Found quality match with " + newQuality);
                                    window.hls.currentLevel = levelIndex;
                                }
                            });
                        }
                    }
                }
                else{
                    notifiMessage('Lỗi khi lấy nội dung học thử!')
                    content_try_loading = false;
                    if($(el).hasClass('btn-content-try')){
                        $(el).html(htmlTry);
                    }
                }
            }).fail(() => {
            notifiMessage('Lỗi khi lấy nội dung học thử!')
            content_try_loading = false;
            if($(el).hasClass('btn-content-try')){
                $(el).html(htmlTry);
            }
        })
    }

